import{_ as t,c as a,a3 as p,o as s}from"./chunks/framework.75m7UlQd.js";const m=JSON.parse('{"title":"《凡人修仙传》时间线梳理","description":"","frontmatter":{"title":"《凡人修仙传》时间线梳理","tags":["读后感"],"categories":["成长录\\r"],"date":"2024-10-03T19:34:29.000Z","abbrlink":24100319,"updated":"2024-10-03 19:35"},"headers":[],"relativePath":"blog-essays/《凡人修仙传》时间线梳理.md","filePath":"blog-essays/《凡人修仙传》时间线梳理.md"}'),r={name:"blog-essays/《凡人修仙传》时间线梳理.md"};function o(_,e,n,c,d,i){return s(),a("div",null,e[0]||(e[0]=[p("<p>《凡人修仙传》情节涉及时间线的交错，构思如此精妙，读毕后梳理一下时间顺序。</p><p>最古早的背景：天地生于混沌，掌天瓶是自混沌中生出的第一件玄天之宝，可容世间所有法则。</p><p>大BOSS背景：古或今时间法则证道，受天道侵蚀，故想吸收世间所有道祖融合三千大道成就混沌道祖，重开天地。混沌法则凌驾于时间、轮回、空间三大至尊法则之上，只有三大法则联合才有一丝希望对抗混沌法则。</p><p>故事开始（非小说视角）：<br> 韩立出生后，资质低下，没有掌天瓶，用比小说还精彩的未知经历从人界到仙界，一路修时间法则，不知何时得到掌天瓶，后面打不过古或今，情急之下将一身时间法则注入掌天瓶，掌天瓶产生了瓶灵并有了穿越时空的能力，韩立穿越到韩立出生的千万年之前，穿越时丢失了掌天瓶，韩立凭借经验转修轮回法则，成为轮回殿主。其中穿越时，掌天瓶遗失在时空乱流中，在韩立未出生的时间点上，被李元究捡到，李元究修成金之道祖，后被骷颅哥盗走掌天瓶，掌天瓶的瓶灵落入魔界魔源海，瓶身落到韩立村落附近。</p><p>而后，小说从此刻展开，即“轮回韩立”穿越后的千万年之后，韩立刚出生后，这一时间点上故事徐徐展开，此时轮回韩立已经修道千万年，而其所在时间线上的韩立刚出生不久。主角韩立（小说视角）出生后，主角韩立捡到掌天瓶，按照小说内容，从人界到灵界到仙界，修时间法则。</p><p>两个韩立分别简称为轮回韩立和时间韩立（主角视角），乃是同一人，只是因轮回韩立利用时间法则和掌天瓶穿越导致与小说视角的时间韩立同处一条时间线。</p><p>自此，轮回韩立穿越后修了轮回法则，主角视角的时间韩立修了时间法则，魔主则修的空间法则，三大法则联合掌天瓶，将古或今的混沌法则封入掌天瓶，并击杀了古或今，轮回韩立与魔主身死道消，时间韩立将自身时间法则封入掌天瓶后避免了天道的侵蚀，从此逍遥快活。</p><p>轮回韩立只爱甘如霜一人，主角时间韩立美女成群。韩立伪四灵根，资质底下，轮回韩立没有掌天瓶这个外挂，但主角时间韩立有掌天瓶这个外挂，这是富二代啊，可见《凡人修仙传》这个名讳，除了显含世俗的勾心斗角、明争暗斗以外，某种程度上也暗示了轮回韩立的修仙传哈哈哈</p><p>杀人放火厉飞雨，救苦救难韩天尊。修仙界的风云波谲，世间的恩爱情仇，纷繁交错，问心无愧便是。</p>",9)]))}const f=t(r,[["render",o]]);export{m as __pageData,f as default};
